#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int countLE(int *row, int m, int val) {
    int lo = 0, hi = m; // hi is exclusive
    while (lo < hi) {
        int mid = lo + (hi - lo) / 2;
        if (row[mid] <= val) lo = mid + 1;
        else hi = mid;
    }
    return lo; // number of elements <= val
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        int **mat = (int**)malloc(N * sizeof(int*));
        int minVal = INT_MAX, maxVal = INT_MIN;
        for (int i = 0; i < N; ++i) {
            mat[i] = (int*)malloc(M * sizeof(int));
            for (int j = 0; j < M; ++j) {
                scanf("%d", &mat[i][j]);
                if (j == 0 && mat[i][j] < minVal) minVal = mat[i][j];
                if (j == M-1 && mat[i][j] > maxVal) maxVal = mat[i][j];
            }
        }
        int desired = (N * M + 1) / 2;
        while (minVal < maxVal) {
            int mid = minVal + (maxVal - minVal) / 2;
            long long cnt = 0;
            for (int i = 0; i < N; ++i) cnt += countLE(mat[i], M, mid);
            if (cnt < desired) minVal = mid + 1;
            else maxVal = mid;
        }
        printf("%d\n", minVal);
        for (int i = 0; i < N; ++i) free(mat[i]);
        free(mat);
    }
    return 0;
}

