const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = input[idx++];
  const M = input[idx++];
  const matrix = new Array(N);
  let low = Number.MAX_SAFE_INTEGER;
  let high = Number.MIN_SAFE_INTEGER;
  for (let i = 0; i < N; ++i) {
    const row = new Array(M);
    for (let j = 0; j < M; ++j) {
      row[j] = input[idx++];
    }
    matrix[i] = row;
    low = Math.min(low, row[0]);
    high = Math.max(high, row[M-1]);
  }
  const need = Math.floor((N * M + 1) / 2);
  while (low < high) {
    const mid = Math.floor(low + (high - low) / 2);
    let cnt = 0;
    for (let i = 0; i < N; ++i) {
      // binary search in row
      let lo = 0, hi = M;
      while (lo < hi) {
        const m = (lo + hi) >> 1;
        if (matrix[i][m] <= mid) lo = m + 1; else hi = m;
      }
      cnt += lo;
    }
    if (cnt < need) low = mid + 1; else high = mid;
  }
  outputs.push(String(low));
}
console.log(outputs.join('\n'));
